(window.webpackJsonp=window.webpackJsonp||[]).push([[16],{359:function(t,n,e){"use strict";e.r(n);var r=e(3),s=Object(r.a)({},(function(){var t=this,n=t.$createElement,e=t._self._c||n;return e("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[e("h1",{attrs:{id:"заметка-о-коnnективном-разуме"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#заметка-о-коnnективном-разуме"}},[t._v("#")]),t._v(" Заметка о коллективном разуме")]),t._v(" "),e("p",[t._v('Как оказалось, между двумя людьми может существовать не просто общий склад ума, но и куда более общая "когерентность мозга", например когда у двоих людей общий ход мысли, им нравятся одни вещи, и у них одинаковое отношение не только в плане "нравятся одинаковые вещи", но и в плане что эти люди приходят к одинаковым мыслям, и их умозаключения могут настолько совпадать, что один человек может быть точно уверен в том, что второй человек подумал о том же. Заметил я это совершенно случайно и на собственном опыте.\nИсходя из этой когерентности, родилась мысль создать коллективный разум, и разумеется что больше всего для него подошли бы именно такие люди. Идея коллективного разума, к слову говоря, так же пришла к нам обоим практически синхронно. Основывается она на принципе "взаимодействуй но не смешивай", т.е. речь идёт не об слиянии двух разумов, как это могло быть в научно-фантастической повести, а об двух независимых разумах, каждый из которых берёт на себя спецификацию в некоторых областях науки, и между двумя разумами устанавливается канал связи (не-не-не! не связывать два мозга, достаточно обычной коммуникации). Хак заключается в том, что два человека принимают позицию друг-друга как свою собственную, что приводит к существенной экономии и повышению производительность, а в целом мы получаем "абстрактный разум состоящий из двух реальных".')]),t._v(" "),e("p",[t._v('Вариант коллективного разума в одной лаборатории. Смысл заключается в том, что два человека при плотной совместной работе в одной лаборатории (при условии описанном в начале статьи), спустя какое-то время, гипотетически можно придти к называемой "телепатии", когда два человека просто понимают друг-друга без слов. Но магии здесь нет, хак работает на основе способности мозга к предсказанию событий (одна из теорий о том как работает мозг), а поскольку есть такая высокая "когерентность", то это всё равно что предсказывать свои действия, т.е. прогноз увеличивается в сторону большей достоверности.')]),t._v(" "),e("p",[t._v('Вариант с использованием унифицированного языка. Было замечено, что, например русский язык в отличии от китайского не базируется на образности (иероглифы произошли в результате пиктографирования, по крайней мере изначальные). Часто люди описывают одно и тоже явление различными словами, и это вызывает баг, который можно назвать как "спор об одном и том же". Конечно суть этой проблемы кроется в формальном описании, и легко решается если перейти на представление образами. Но ведь было бы затруднительно общаться с кем-либо без языка? Тут появилась идея метаязыка, основанного на образных символах, но могущих менять своё значение в зависимости от конфигурации. Это сугубо письменный язык, и при определённом уровне плотности можно вкладывать громадные объёмы информации в маленький объём. Для облегчения можно использовать специально устройство, которое носило кодовое название Personal Bulletin Board (PBS). Суть его проста: обычная электронная бумага, с памятью и возможностью ручного письма. Для улучшенной работы, предполагалась мгновенная синхронизация между двумя устройствами. Изюминкой языка должна была стать способность выражать образы, при этом в основу должны были лечь исследования мозга и предполагаемая возможность возбуждать одинаковые ансамбли при восприятии символов.')]),t._v(" "),e("p",[t._v("Всё это сугубо гипотетические соображения, рождённые некоторое время назад, когда я ещё не был близко знаком ни с нейробиологией ни с эпистемологией. В данный момент я никак не работают с ними, не развиваю, и ничего не думаю на этот счёт. Поделился на всякий случай, может быть кому-то будет интересно.")])])}),[],!1,null,null,null);n.default=s.exports}}]);